  1	import { type ComponentProps, type ForwardedRef, forwardRef, useMemo } from 'react';
  2	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
  3	
  4	import { ExternalLink } from '@components/common/ExternalLink/ExternalLink';
  5	import Select from '@components/common/Select';
  6	import {
  7	  StorageMapModelGroupVersionKind,
  8	  StorageMapModelRef,
  9	  type V1beta1StorageMap,
 10	} from '@kubev2v/types';
 11	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 12	import {
 13	  EmptyState,
 14	  EmptyStateBody,
 15	  EmptyStateVariant,
 16	  SelectList,
 17	  SelectOption,
 18	  Title,
 19	} from '@patternfly/react-core';
 20	import { getName } from '@utils/crds/common/selectors';
 21	import { isEmpty } from '@utils/helpers';
 22	import { useForkliftTranslation } from '@utils/i18n';
 23	
 24	type StorageMapSelectProps = Pick<ComponentProps<typeof Select>, 'onSelect' | 'status'> & {
 25	  id: string;
 26	  value: string;
 27	  namespace: string;
 28	  includeOwnerReferenced?: boolean;
 29	  testId?: string;
 30	};
 31	
 32	const StorageMapSelect = (
 33	  {
 34	    id,
 35	    includeOwnerReferenced = false,
 36	    namespace,
 37	    onSelect,
 38	    status,
 39	    testId,
 40	    value,
 41	  }: StorageMapSelectProps,
 42	  ref: ForwardedRef<HTMLButtonElement>,
 43	) => {
 44	  const { t } = useForkliftTranslation();
 45	  const [allStorageMaps] = useK8sWatchResource<V1beta1StorageMap[]>({
 46	    groupVersionKind: StorageMapModelGroupVersionKind,
 47	    isList: true,
 48	    namespace,
 49	  });
 50	
 51	  const storageMapsListUrl = getResourceUrl({
 52	    namespace,
 53	    reference: StorageMapModelRef,
 54	  });
 55	
 56	  // Filter out storage maps that have ownerReferences unless includeOwnerReferenced is true
 57	  const storageMaps = useMemo(() => {
 58	    if (!allStorageMaps) {
 59	      return [];
 60	    }
 61	    if (includeOwnerReferenced) {
 62	      return allStorageMaps;
 63	    }
 64	
 65	    return allStorageMaps.filter((storageMap) => {
 66	      return isEmpty(storageMap.metadata?.ownerReferences);
 67	    });
 68	  }, [allStorageMaps, includeOwnerReferenced]);
 69	
 70	  const emptyState = (
 71	    <EmptyState variant={EmptyStateVariant.xs}>
 72	      <Title headingLevel="h4" size="md">
 73	        {t('You do not have any storage maps without owner references.')}
 74	      </Title>
 75	      <EmptyStateBody>
 76	        <ExternalLink href={`${storageMapsListUrl}/~new`} isInline>
 77	          {t('Create a storage map without an owner')}
 78	        </ExternalLink>
 79	      </EmptyStateBody>
 80	    </EmptyState>
 81	  );
 82	
 83	  return (
 84	    <Select
 85	      id={id}
 86	      ref={ref}
 87	      value={value}
 88	      status={status}
 89	      onSelect={onSelect}
 90	      placeholder={t('Select storage map')}
 91	      testId={testId}
 92	    >
 93	      <SelectList>
 94	        {isEmpty(storageMaps)
 95	          ? emptyState
 96	          : storageMaps.map((storageMap) => {
 97	              const storageMapName = getName(storageMap);
 98	
 99	              return (
100	                <SelectOption key={storageMapName} value={storageMap}>
101	                  {storageMapName}
102	                </SelectOption>
103	              );
104	            })}
105	      </SelectList>
106	    </Select>
107	  );
108	};
109	
110	export default forwardRef(StorageMapSelect);

